#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<ll, ll>PII
using namespace std;
CI MAXN=5e1+5;
const ll MOD=2147483648;
ll n,f[MAXN];
void init()
{
	f[1]=f[2]=1;
	for(int i=3;i<=n;++i)
	{
		f[i]=(f[i-1]+f[i-2])%MOD;
	}
}
void print()
{
	printf("%lld=",f[n]);
	while(true)
	{
		for(ll i=2ll;i<=f[n];++i)
		{
			if(f[n]%i==0)
			{
				if(f[n]/i==1)
				{
					printf("%lld",i);
					exit(false);
				} 
				else printf("%lld*",i);
				f[n]/=i;
				break;
			}
			
		}
	}
}
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%lld",&n);
	init();
	print();
	return false;
}
